import os
import time
import requests


def main(event):
    token = os.getenv("token")
    session = requests.Session()
    session.headers.update({
        "Authorization": f"Bearer {token}",
        "Content-Type": "application/json",
    })
    url = "https://api.hubapi.com/crm/v3/objects/deals/search"

    SEQ_PROP = "project_number_value"   # numeric + unique -> primary path
    TEXT_PROP = "project_number"        # legacy text "PROJ-9891" -> bootstrap fallback
    BASE = 1000                         # floor if neither field has any data

    def search(payload):
        # Short, bounded backoff so we stay well under the 20s action limit.
        for attempt in range(3):
            resp = session.post(url, json=payload, timeout=10)
            if resp.status_code == 429:
                time.sleep(0.4 * (2 ** attempt))
                continue
            resp.raise_for_status()
            return resp.json()
        resp.raise_for_status()
        return resp.json()

    # ---- Primary: numeric server-side sort. Sorts numerically, so it is safe
    # across the 9999 -> 10000 rollover. Fast (limit=1) once the property exists.
    data = search({
        "filterGroups": [
            {"filters": [{"propertyName": SEQ_PROP, "operator": "HAS_PROPERTY"}]}
        ],
        "properties": [SEQ_PROP],
        "sorts": [{"propertyName": SEQ_PROP, "direction": "DESCENDING"}],
        "limit": 1,
    })

    highest = None
    results = data.get("results", [])
    if results:
        raw = results[0].get("properties", {}).get(SEQ_PROP)
        try:
            highest = int(float(raw))  # HubSpot may return "9891" or "9891.0"
        except (TypeError, ValueError):
            highest = None

    # ---- Fallback: bootstraps from the text field while project_number_value
    # is empty. Sorts by CREATEDATE (newest deal = highest number) rather than
    # the text value, so it is NOT affected by the 4 -> 5 digit boundary.
    if highest is None:
        fb = search({
            "filterGroups": [
                {"filters": [{"propertyName": TEXT_PROP, "operator": "HAS_PROPERTY"}]}
            ],
            "properties": [TEXT_PROP, "createdate"],
            "sorts": [{"propertyName": "createdate", "direction": "DESCENDING"}],
            "limit": 50,
        })
        for rec in fb.get("results", []):
            raw = rec.get("properties", {}).get(TEXT_PROP, "") or ""
            parts = raw.split("-")
            if len(parts) == 2:
                try:
                    n = int(parts[1])
                except ValueError:
                    continue
                if highest is None or n > highest:
                    highest = n

    if highest is None:
        highest = BASE

    next_number = highest + 1

    return {
        "outputFields": {
            "project_number": f"PROJ-{next_number}",
            "project_number_value": next_number,
        }
    }
